            {marketplaceContent && renderMarketplaceContent()}
          </Box>


          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="ghostLarge"
              text="Relatar Problema"
              onPress={handleOpenReportProblem}
            />
          </Box>
        </Box>

      </BasicScreen>

      <BackDropBottom
        modalizeRef={modalizeRef as PropsModalizeRef}
      >
        <Box align="center" width="100%" mt="xxs">
          <Box align="center" width="100%">
            <Text type="paragraphXXXL" color="BRAND_COMPLEMENT_01" mb="xs" align="center">
              Central de Atendimento
            </Text>
          </Box>
        </Box>

        <Box pd="innerSmall">
          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Capitais"
            description="4002 1552"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_capitais',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });
              Linking.openURL('tel:40021552');
            }}
          />

          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Demais localidades"
            description="0800 015 0252"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_demais_localidades',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });

              Linking.openURL('tel:08000150252');
            }}
          />
          <Text type="paragraphXS" color="INTENSE_COLOR_04" mt='xxxxs'>
            *Atendimento de segunda à sexta das 9h às 21h. Sábado e domingo das 9h às 17h.
          </Text>


        </Box>

        <Box align="center" width="100%" mt='xxxxs'>
          <Text type="linkMD" color="INTENSE_COLOR_05" onPress={handleCloseReportProblem} align="center">
            Fechar
          </Text>
        </Box>
      </BackDropBottom>

      {isCashback && (
        <BackDropBottom modalHeight={height * 0.30} modalizeRef={modalizeRefInfo as PropsModalizeRef}>
          <Text
            type="paragraphMD"
            align="center"
            color="INTENSE_COLOR_05"
            mt="small"
            mb="smaller"
          >
            Você também pode conferir o valor do desconto nos lançamentos da sua fatura.
          </Text>

          <Button text="Entendi" onPress={handleCloseInfo} />
        </BackDropBottom>
      )}
    </>
  );
};

export default MyOrdersDetailView;

